import React, { useState } from "react";
import { motion, useAnimation } from "framer-motion";

const TestimonialCard = ({ testimonial }) => {
  const [flipped, setFlipped] = useState(false);
  const controls = useAnimation();

  const {
    text = "I replaced coffee with a healthy alternative that keeps me energized all day long, without any crashes or jitters.",
  } = testimonial || {};

  const handleClick = () => {
    setFlipped((prev) => !prev);
    controls.start({
      rotateY: flipped ? 0 : 180,
      transition: { duration: 0.6 },
    });
  };

  return (
    <motion.div
      style={{
        width: "320px",
        minHeight: "300px",
        perspective: 1000,
        cursor: "pointer",
      }}
      onClick={handleClick}
      animate={controls}
      initial={{ rotateY: 0 }}
    >
      {/* Contenedor para el frente y atrás */}
      <motion.div
        style={{
          position: "relative",
          width: "100%",
          height: "100%",
          borderRadius: "10px",
          backgroundColor: "#154734",
          color: "#e4d0a9",
          boxShadow: "0 2px 8px rgba(0,0,0,0.3)",
          padding: "2rem",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          textAlign: "center",
          backfaceVisibility: "hidden",
          WebkitBackfaceVisibility: "hidden",
          rotateY: 0,
          position: "absolute",
          top: 0,
          left: 0,
        }}
      >
        {/* Frente */}
        <div style={{ marginBottom: "1.5rem", fontWeight: "bold", fontSize: "1.3rem" }}>
          Frontend
        </div>
        <p style={{ marginBottom: "1rem", fontSize: "1rem", lineHeight: "1.5" }}>
          "{text}"
        </p>
        <div style={{ fontSize: "0.9rem", fontWeight: "400", opacity: 0.8 }}>
          Productor
        </div>
      </motion.div>

      <motion.div
        style={{
          position: "absolute",
          width: "100%",
          height: "100%",
          borderRadius: "10px",
          backgroundColor: "#e4d0a9",
          color: "#154734",
          boxShadow: "0 2px 8px rgba(0,0,0,0.3)",
          padding: "2rem",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          textAlign: "center",
          backfaceVisibility: "hidden",
          WebkitBackfaceVisibility: "hidden",
          rotateY: 180,
          top: 0,
          left: 0,
          pointerEvents: "none", // para evitar interacción en la parte trasera
        }}
      >
        {/* Atrás */}
        <h3 style={{ fontWeight: "bold", fontSize: "1.5rem", marginBottom: "1rem" }}>
          Información adicional
        </h3>
        <p style={{ fontSize: "1rem", lineHeight: "1.5" }}>
          Aquí puedes poner más detalles del testimonio, datos de contacto, o cualquier texto que quieras mostrar al girar la tarjeta.
        </p>
      </motion.div>
    </motion.div>
  );
};

export default TestimonialCard;
